// https://projecteuler.net/problem=008

// cargo run -p euler_008 --release

// use euler_utils::*;

const NUMBER: &str = "";

fn product_of_d(mut n: u64) -> u64 {
    if n == 0 {
        return 0;
    }
    let mut prod: u64 = 1;
    while n > 0 {
        let d = n % 10;
        if d == 0 {
            return 0;
        }
        prod *= d;
        n /= 10;
    }
    prod
}

fn solve(l: usize) -> u64 {
    let mut i: usize = 0;
    let mut prod: u64 = 0;

    while i <= NUMBER.len() - l {
        let mut n: u64 = NUMBER[i..i + l].parse().expect("nie mozna sparsowac");
        n = product_of_d(n);

        if n > prod {
            prod = n;
        }
        i += 1;
    }
    prod
}

fn main() {
    let answer = solve(13);
    println!("rozwiązanie dla zadania 008: {}", answer);
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_example() {
        assert_eq!(solve(4), 5832);
    }
}
